<?php
namespace App\Modules\Hr\Analytics\Livewire;use App\Modules\Hr\Analytics\Actions\BuildHrAnalyticsSnapshotAction;use App\Modules\Hr\Analytics\Models\HrAnalyticsSnapshot;use App\Modules\Hr\Core\Services\TenantContext;use Livewire\Component;
class HrAnalyticsDashboard extends Component{public string $periodStart='';public string $periodEnd='';public function mount():void{$this->periodStart=today()->startOfYear()->toDateString();$this->periodEnd=today()->toDateString();}public function generate(BuildHrAnalyticsSnapshotAction $action):void{$this->validate(['periodStart'=>'required|date','periodEnd'=>'required|date']);$action->execute($this->periodStart,$this->periodEnd);session()->flash('success','Kaynak izli analitik anlık görüntüsü oluşturuldu.');}public function render(){return view('livewire.hr.analytics.hr-analytics-dashboard',['snapshots'=>HrAnalyticsSnapshot::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->latest('generated_at')->limit(12)->get()])->layout('layouts.app');}}
